// ---- Launch cities --------------------------------------------------------
const CITIES = [
  { name: "Algiers",     lat: 36.7538, lng: 3.0588,  primary: true  },
  { name: "Oran",        lat: 35.6976, lng: -0.6337                 },
  { name: "Constantine", lat: 36.3650, lng: 6.6147                  },
  { name: "Bejaia",      lat: 36.7525, lng: 5.0840                  },
  { name: "Tipaza",      lat: 36.5894, lng: 2.4439                  },
  { name: "Batna",       lat: 35.5500, lng: 6.1739                  },
  { name: "Ghardaia",    lat: 32.4900, lng: 3.6700                  },
  { name: "Djanet",      lat: 24.5544, lng: 9.4843                  },
];

// =============================================================================
// 3D Math
// =============================================================================
//
// Pipeline: (lng, lat) -> point on unit sphere
//        -> rotate by current yaw around vertical axis
//        -> rotate by fixed pitch (forward tilt of the camera)
//        -> orthographic projection: x stays x, y stays y, z = depth.
// A dot is visible if its z (depth) is positive after rotation, i.e. facing
// the camera.
//
// Camera setup: we orient the globe so that lat ~28°N, lng ~3°E (Algeria's
// rough center) sits at the front (z = +1) when yaw = 0. We do that by
// pre-shifting lng so that the country's center longitude becomes 0, then
// applying a positive pitch to bring the latitude band into view.
// =============================================================================

const VIEW_LNG = 3;     // longitude that should be front-facing at yaw=0
const VIEW_LAT = 27;    // latitude that should be at the equator of view
const PITCH_DEG = VIEW_LAT;  // rotate the sphere so VIEW_LAT comes up to center
const PITCH_RAD = (PITCH_DEG * Math.PI) / 180;
const COS_PITCH = Math.cos(PITCH_RAD);
const SIN_PITCH = Math.sin(PITCH_RAD);

function project3D(lng, lat, yawDeg) {
  // Shift longitude so view center is at 0
  const effLng = lng - VIEW_LNG - yawDeg;
  const lambda = (effLng * Math.PI) / 180;
  const phi    = (lat * Math.PI) / 180;

  // Sphere point — convention: y up (north), x east, z toward camera
  const cosPhi = Math.cos(phi);
  let x = cosPhi * Math.sin(lambda);
  let y = Math.sin(phi);
  let z = cosPhi * Math.cos(lambda);

  // Pitch: rotate around the X axis so that latitude band VIEW_LAT comes
  // forward. After this transformation, a point originally at (0, VIEW_LAT)
  // is at (0, 0, 1) — dead center of the front face.
  const y2 = y * COS_PITCH - z * SIN_PITCH;
  const z2 = y * SIN_PITCH + z * COS_PITCH;

  return { x, y: y2, z: z2 };
}

// =============================================================================
// Component
// =============================================================================
export default function AlgeriaGlobe() {
  const { t } = useLang();

  // SVG canvas
  const W = 760;
  const H = 600;
  const CX = W / 2;
  const CY = H / 2;
  const R  = 240;   // sphere radius in pixels

  // Continuous rotation phase. Yaw increments each frame.
  // Animation timer separate from yaw so shimmer/arc logic can read it too.
  const [tick, setTick] = useState(0);
  const yawRef = useRef(0);
  const phaseRef = useRef(0);
  const rafRef = useRef(null);

  useEffect(() => {
    let last = performance.now();
    function frame(now) {
      const dt = Math.min(now - last, 80) / 1000;
      last = now;
      yawRef.current += dt * 3.5;   // degrees per second — slow, hypnotic
      phaseRef.current += dt;
      setTick((t) => t + 1);
      rafRef.current = requestAnimationFrame(frame);
    }
    rafRef.current = requestAnimationFrame(frame);
    return () => cancelAnimationFrame(rafRef.current);
  }, []);

  const yawDeg = yawRef.current;
  const phase = phaseRef.current;

  // ---- City projections at current rotation -------------------------------
  const cityProj = useMemo(() => {
    return CITIES.map((c) => {
      const p = project3D(c.lng, c.lat, yawDeg);
      return {
        ...c,
        sx: CX + p.x * R,
        sy: CY - p.y * R,
        sz: p.z,        // > 0 = visible
      };
    });
  }, [yawDeg]);

  // ---- Travel arcs (3D-aware) ---------------------------------------------
  const ARC_LIFETIME = 2.8;
  const ARC_SPAWN_INTERVAL = 1.7;
  const arcsRef = useRef([]);
  const lastSpawnRef = useRef(0);
  const cascadeUntilRef = useRef(0);

  // Clean expired arcs, spawn new
  if (arcsRef.current.length > 0) {
    arcsRef.current = arcsRef.current.filter((a) => phase - a.born < ARC_LIFETIME);
  }
  const spawnGap = phase < cascadeUntilRef.current ? 0.18 : ARC_SPAWN_INTERVAL;
  if (phase - lastSpawnRef.current > spawnGap) {
    lastSpawnRef.current = phase;
    const a = Math.floor(Math.random() * CITIES.length);
    let b = Math.floor(Math.random() * CITIES.length);
    if (b === a) b = (b + 1) % CITIES.length;
    arcsRef.current.push({ from: a, to: b, born: phase });
  }

  // ---- Click handler ------------------------------------------------------
  const [cascadeKey, setCascadeKey] = useState(0);
  function handleSpark() {
    cascadeUntilRef.current = phase + 1.6;
    setCascadeKey((k) => k + 1);
  }

  // ---- Arc path: cubic curve approximating a great-circle arc ------------
  function arcPath(fromIdx, toIdx) {
    const a = cityProj[fromIdx];
    const b = cityProj[toIdx];
    if (a.sz < 0 || b.sz < 0) return null; // both endpoints must be visible
    const mx = (a.sx + b.sx) / 2;
    const my = (a.sy + b.sy) / 2;
    const dx = b.sx - a.sx;
    const dy = b.sy - a.sy;
    const dist = Math.sqrt(dx * dx + dy * dy);
    const lift = Math.min(80, dist * 0.4);
    // Lift toward the screen-up direction (negative y)
    return `M ${a.sx} ${a.sy} Q ${mx} ${my - lift} ${b.sx} ${b.sy}`;
  }

  // ---- Dot rendering ------------------------------------------------------
  // We compute every dot's screen position every frame. For each dot:
  //   1. Project 3D with current yaw
  //   2. If z < ~-0.02, dot is on the back hemisphere — skip
  //   3. Opacity scales with z (front-facing dots brighter)
  //
  // This runs each frame for ~2900 dots. To keep it cheap we render via SVG
  // <circle> elements but skip back-facing dots.

  function renderDots() {
    const out = [];
    // World dots: dim
    for (let i = 0; i < WORLD_DOTS.length; i += 2) {
      const lng = WORLD_DOTS[i];
      const lat = WORLD_DOTS[i + 1];
      const p = project3D(lng, lat, yawDeg);
      if (p.z < -0.02) continue;
      // opacity ramps from 0 at the limb to ~0.22 at center
      const t = (p.z + 0.02) / 1.02;
      const opacity = 0.05 + t * 0.20;
      out.push(
        <circle key={`w${i}`}
          cx={CX + p.x * R} cy={CY - p.y * R} r="1.2"
          fill="#16161A" opacity={opacity} />
      );
    }
    // Algeria dots: bold red
    for (let i = 0; i < ALG_DOTS.length; i += 2) {
      const lng = ALG_DOTS[i];
      const lat = ALG_DOTS[i + 1];
      const p = project3D(lng, lat, yawDeg);
      if (p.z < -0.02) continue;
      const t = (p.z + 0.02) / 1.02;
      // Algeria gets stronger opacity and red color
      // plus subtle shimmer based on phase
      const shimmer = Math.sin(phase * 1.2 + lng * 0.4 + lat * 0.3) * 0.18;
      const opacity = Math.max(0.3, 0.55 + t * 0.4 + shimmer);
      out.push(
        <circle key={`a${i}`}
          cx={CX + p.x * R} cy={CY - p.y * R} r="1.7"
          fill="#E63946" opacity={opacity} />
      );
    }
    return out;
  }

  // ---- Grid lines (meridians and parallels) ------------------------------
  // We draw lat/lng grid as polylines on the visible hemisphere.
  function renderGrid() {
    const lines = [];
    const SAMPLES = 60;

    // Helper: build a path 'd' string from a sampled great-circle path,
    // breaking it into separate M-L segments wherever the line dips behind
    // the sphere.
    function buildPath(samples) {
      let d = "";
      let inSegment = false;
      for (const s of samples) {
        if (s.visible) {
          if (!inSegment) {
            d += `M ${s.x.toFixed(1)} ${s.y.toFixed(1)} `;
            inSegment = true;
          } else {
            d += `L ${s.x.toFixed(1)} ${s.y.toFixed(1)} `;
          }
        } else {
          inSegment = false;
        }
      }
      return d.trim();
    }

    // Meridians every 30°
    for (let meridLng = -180; meridLng < 180; meridLng += 30) {
      const samples = [];
      for (let s = 0; s <= SAMPLES; s++) {
        const lat = -85 + (s / SAMPLES) * 170;
        const p = project3D(meridLng, lat, yawDeg);
        samples.push({
          x: CX + p.x * R,
          y: CY - p.y * R,
          visible: p.z > 0,
        });
      }
      const d = buildPath(samples);
      if (d) {
        lines.push(
          <path key={`mer${meridLng}`} d={d} fill="none"
                stroke="#16161A" strokeOpacity="0.08" strokeWidth="0.8" />
        );
      }
    }

    // Parallels every 30°
    for (let parLat = -60; parLat <= 60; parLat += 30) {
      const samples = [];
      for (let s = 0; s <= SAMPLES; s++) {
        const lng = -180 + (s / SAMPLES) * 360;
        const p = project3D(lng, parLat, yawDeg);
        samples.push({
          x: CX + p.x * R,
          y: CY - p.y * R,
          visible: p.z > 0,
        });
      }
      const d = buildPath(samples);
      if (d) {
        lines.push(
          <path key={`par${parLat}`} d={d} fill="none"
                stroke="#16161A" strokeOpacity="0.08" strokeWidth="0.8" />
        );
      }
    }

    return lines;
  }

  const algiers = cityProj.find((c) => c.primary);
  const djanet  = cityProj.find((c) => c.name === "Djanet");

  return (
    <section className="nz-globe-section">
      <div className="wrap nz-globe-head">
        <div className="nz-globe-kicker">{t("globe.kicker")}</div>
        <h2 className="display nz-globe-title">{t("globe.title")}</h2>
        <p className="nz-globe-sub">{t("globe.sub")}</p>
      </div>

      <div
        className="nz-globe-stage"
        onClick={handleSpark}
        role="button"
        tabIndex={0}
        aria-label="Activate the network"
        onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") handleSpark(); }}
      >
        {/* Callouts */}
        <div className="nz-globe-callout nz-globe-callout-left">
          <div className="nz-globe-callout-num display">10</div>
          <div className="nz-globe-callout-body">
            <div className="nz-globe-callout-title">{t("globe.callout1_t")}</div>
            <div className="nz-globe-callout-text">{t("globe.callout1_d")}</div>
          </div>
        </div>

        <div className="nz-globe-callout nz-globe-callout-right">
          <div className="nz-globe-callout-body">
            <div className="nz-globe-callout-title">{t("globe.callout2_t")}</div>
            <div className="nz-globe-callout-text">{t("globe.callout2_d")}</div>
          </div>
        </div>

        <svg className="nz-globe-svg" viewBox={`0 0 ${W} ${H}`}
             xmlns="http://www.w3.org/2000/svg" aria-hidden>
          <defs>
            <radialGradient id="nz-globe-halo" cx="50%" cy="50%" r="50%">
              <stop offset="0%"   stopColor="#E63946" stopOpacity="0.10" />
              <stop offset="55%"  stopColor="#E63946" stopOpacity="0.04" />
              <stop offset="100%" stopColor="#E63946" stopOpacity="0" />
            </radialGradient>
            <radialGradient id="nz-globe-shade" cx="35%" cy="35%" r="75%">
              <stop offset="0%"   stopColor="#FAF8F4" stopOpacity="0" />
              <stop offset="100%" stopColor="#16161A" stopOpacity="0.06" />
            </radialGradient>
            <filter id="nz-pin-glow">
              <feGaussianBlur stdDeviation="2.5" result="blur" />
              <feMerge>
                <feMergeNode in="blur" />
                <feMergeNode in="SourceGraphic" />
              </feMerge>
            </filter>
          </defs>

          {/* Halo */}
          <circle cx={CX} cy={CY} r={R * 1.32} fill="url(#nz-globe-halo)" />
          {/* Subtle sphere shading */}
          <circle cx={CX} cy={CY} r={R} fill="url(#nz-globe-shade)" />

          {/* Lat/lng grid */}
          <g>{renderGrid()}</g>

          {/* Dotted continents + Algeria */}
          <g>{renderDots()}</g>

          {/* Travel arcs */}
          <g>
            {arcsRef.current.map((a, i) => {
              const d = arcPath(a.from, a.to);
              if (!d) return null;
              const age = phase - a.born;
              const t = age / ARC_LIFETIME;
              let opacity;
              if (t < 0.25) opacity = t / 0.25;
              else if (t > 0.75) opacity = (1 - t) / 0.25;
              else opacity = 1;
              opacity *= 0.7;
              return (
                <path key={`arc-${a.born}-${i}`}
                  d={d} fill="none" stroke="#E63946"
                  strokeWidth="1.4" strokeOpacity={opacity}
                  strokeDasharray="3 4" strokeLinecap="round" />
              );
            })}
          </g>

          {/* City pins */}
          <g>
            {cityProj.map((c, i) => {
              if (c.sz < 0) return null;
              const vis = Math.max(0, c.sz);
              return (
                <g key={c.name} opacity={0.5 + vis * 0.5}>
                  <circle cx={c.sx} cy={c.sy} r="5"
                    fill="#E63946" className="nz-globe-pulse"
                    style={{ animationDelay: `${i * 0.35}s` }} />
                  {cascadeKey > 0 && (
                    <circle key={`c${cascadeKey}-${i}`}
                      cx={c.sx} cy={c.sy} r="5" fill="#E63946"
                      className="nz-globe-cascade"
                      style={{ animationDelay: `${i * 0.06}s` }} />
                  )}
                  <circle cx={c.sx} cy={c.sy} r={c.primary ? 5.5 : 4.5}
                    fill="#E63946" filter="url(#nz-pin-glow)" />
                  {c.primary && (
                    <circle cx={c.sx} cy={c.sy} r="2.2" fill="#FAF8F4" />
                  )}
                </g>
              );
            })}
          </g>

          {/* Leader lines from callouts */}
          <g>
            {algiers && algiers.sz > 0 && (
              <line x1={algiers.sx} y1={algiers.sy}
                x2={CX - R - 30} y2={CY - R * 0.5}
                stroke="#E63946" strokeWidth="1"
                strokeOpacity="0.4" strokeDasharray="2 3" />
            )}
            {djanet && djanet.sz > 0 && (
              <line x1={djanet.sx} y1={djanet.sy}
                x2={CX + R + 30} y2={CY + R * 0.45}
                stroke="#E63946" strokeWidth="1"
                strokeOpacity="0.4" strokeDasharray="2 3" />
            )}
          </g>
        </svg>

        <div className="nz-globe-hint">{t("globe.hint")}</div>
      </div>

      <style>{`
        .nz-globe-section {
          padding: 72px 0 80px;
          background: var(--cream);
          position: relative;
          overflow: hidden;
        }
        .nz-globe-head { text-align: center; margin-bottom: 32px; }
        .nz-globe-kicker {
          font-size: 11px; font-weight: 700; letter-spacing: 0.16em;
          text-transform: uppercase; color: var(--red); margin-bottom: 14px;
        }
        .nz-globe-title {
          font-size: clamp(34px, 5vw, 56px); font-weight: 600;
          letter-spacing: -0.02em; line-height: 1.05;
          color: var(--ink); margin-bottom: 14px;
        }
        .nz-globe-sub {
          font-size: 16px; color: var(--ink-2); max-width: 540px;
          margin: 0 auto; line-height: 1.55;
        }
        .nz-globe-stage {
          position: relative; width: 100%; max-width: 1080px;
          margin: 0 auto; padding: 20px 20px 0;
          cursor: pointer; user-select: none;
        }
        .nz-globe-svg {
          display: block; width: 100%; height: auto;
          max-width: 780px; margin: 0 auto;
        }
        .nz-globe-pulse {
          transform-origin: center; transform-box: fill-box;
          animation: nz-globe-pulse 2.8s cubic-bezier(0.16, 1, 0.3, 1) infinite;
          opacity: 0;
        }
        @keyframes nz-globe-pulse {
          0%   { transform: scale(1);   opacity: 0.7; }
          70%  { transform: scale(3.2); opacity: 0;   }
          100% { transform: scale(3.2); opacity: 0;   }
        }
        .nz-globe-cascade {
          transform-origin: center; transform-box: fill-box;
          animation: nz-globe-cascade 0.9s cubic-bezier(0.16, 1, 0.3, 1);
          opacity: 0;
        }
        @keyframes nz-globe-cascade {
          0%   { transform: scale(1);   opacity: 0.9; }
          100% { transform: scale(5);   opacity: 0;   }
        }

        .nz-globe-callout {
          position: absolute; display: flex; align-items: flex-start;
          gap: 14px;
          background: rgba(250, 248, 244, 0.85);
          backdrop-filter: blur(8px);
          -webkit-backdrop-filter: blur(8px);
          padding: 16px 20px; border-radius: 6px; max-width: 240px;
          font-size: 13.5px; line-height: 1.5; z-index: 2;
          animation: nz-globe-callout-in 0.9s cubic-bezier(0.16, 1, 0.3, 1) both;
        }
        @keyframes nz-globe-callout-in {
          from { opacity: 0; transform: translateY(8px); }
          to   { opacity: 1; transform: translateY(0); }
        }
        .nz-globe-callout-left {
          top: 24%; left: 3%;
          border: 1px solid rgba(230, 57, 70, 0.4);
          border-left: 2px solid var(--red);
          animation-delay: 0.3s;
        }
        .nz-globe-callout-right {
          top: 56%; right: 3%;
          border: 1px solid rgba(230, 57, 70, 0.4);
          border-right: 2px solid var(--red);
          text-align: right;
          animation-delay: 0.5s;
        }
        .nz-globe-callout-num {
          font-size: 32px; font-weight: 600; color: var(--red);
          line-height: 1; letter-spacing: -0.02em;
        }
        .nz-globe-callout-title {
          font-weight: 700; color: var(--ink); margin-bottom: 4px;
        }
        .nz-globe-callout-text { color: var(--ink-2); font-size: 12.5px; }

        .nz-globe-hint {
          position: absolute; bottom: -6px; left: 50%;
          transform: translateX(-50%);
          font-size: 11px; font-weight: 600; letter-spacing: 0.1em;
          text-transform: uppercase; color: var(--gray-400);
          white-space: nowrap; opacity: 0.7; pointer-events: none;
        }

        [dir="rtl"] .nz-globe-callout-left {
          left: auto; right: 3%;
          border-left: 1px solid rgba(230, 57, 70, 0.4);
          border-right: 2px solid var(--red);
          text-align: right;
        }
        [dir="rtl"] .nz-globe-callout-right {
          right: auto; left: 3%;
          border-right: 1px solid rgba(230, 57, 70, 0.4);
          border-left: 2px solid var(--red);
          text-align: left;
        }

        @media (max-width: 860px) {
          .nz-globe-callout { max-width: 200px; padding: 12px 16px; font-size: 12.5px; }
          .nz-globe-callout-num { font-size: 26px; }
          .nz-globe-callout-left  { top: 18%; left: 2%; }
          .nz-globe-callout-right { top: 60%; right: 2%; }
        }
        @media (max-width: 600px) {
          .nz-globe-section { padding: 56px 0 64px; }
          .nz-globe-sub { font-size: 14.5px; padding: 0 20px; }
          .nz-globe-stage { padding: 0 16px; }
          .nz-globe-svg { max-width: 420px; }
          .nz-globe-callout {
            position: static; max-width: none; width: 100%;
            margin: 0; text-align: left;
          }
          [dir="rtl"] .nz-globe-callout-left,
          [dir="rtl"] .nz-globe-callout-right { text-align: right; }
          .nz-globe-callout-left  { margin: 24px auto 12px; }
          .nz-globe-callout-right { margin: 0 auto 8px; }
          .nz-globe-hint {
            position: static; transform: none; display: block;
            text-align: center; margin-top: 24px;
          }
        }

        @media (prefers-reduced-motion: reduce) {
          .nz-globe-pulse, .nz-globe-cascade { animation: none; opacity: 0; }
          .nz-globe-callout { animation: none; }
        }
      `}</style>
    </section>
  );
}
